module register_8bit (
    input clk,
    input reset,
    input load,
    input [7:0] d,
    output reg [7:0] q
);

always @(posedge clk) begin
    if (reset)
        q <= 8'b00000000;
    else if (load)
        q <= d;
end

  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        q <= 8'b11111111;
      end
      else if (load) begin
        q <= ~d;
      end
    end
  end

endmodule

